# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from flask import Flask, request, jsonify
from web3 import Web3

app = Flask(__name__)

# Initialize web3 instance with an Ethereum node URL
w3 = Web3(Web3.HTTPProvider('https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID'))

@app.route('/verify-signature', methods=['POST'])
def verify_signature():
    data = request.json
    message = data.get('message')
    signature = data.get('signature')

    if not message or not signature:
        return jsonify({'error': 'Message and signature are required'}), 400

    # Remove the "0x" prefix from the signature
    if signature.startswith("0x"):
        signature = signature[2:]

    try:
        # Recover the address that signed the message
        recovered_address = w3.eth.account.recover_message(
            Web3.solidityKeccak(['string'], [message]),
            signature=signature
        )

        return jsonify({'recoveredAddress': recovered_address}), 200

    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(port=5000)